# Deobfuscated Code & Explanation

## Deobfuscated Version

```javascript
const TWO_PI = Math.PI * 2;

// Configuration
const config = {
  repulsionK: 4000,
  springK: 0.004,
  damping: 0.92,
  gravity: 0.0003,
  particleMax: 40,
  particleFade: 0.04,
  cameraEase: 0.06
};

// Nodes in the graph
const nodes = [
  { id: "center", label: "Hub",       r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",  label: "Alpha",     r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",   label: "Beta",      r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",  label: "Gamma",     r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",  label: "Delta",     r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon",label: "Epsilon",   r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring connections between nodes
const edges = [
  { a: "center", b: "alpha",   rest: 160, k: 0.006 },
  { a: "center", b: "beta",    rest: 160, k: 0.005 },
  { a: "center", b: "gamma",   rest: 170, k: 0.004 },
  { a: "center", b: "delta",   rest: 170, k: 0.004 },
  { a: "center", b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha",  b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma",  b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha",  b: "epsilon", rest: 200, k: 0.002 }
];

// Camera state
let camera = { x: 400, y: 300, zoom: 1 };
let cameraTarget = { x: 400, y: 300, zoom: 1 };
let particles = [];
let frameCount = 0;

function findNode(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics simulation step
function simulatePhysics() {
  // 1. Node-node repulsion (like charges repelling)
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      let dx = nodes[i].x - nodes[j].x;
      let dy = nodes[i].y - nodes[j].y;
      let dist = Math.sqrt(dx * dx + dy * dy) || 1;
      let force = config.repulsionK / (dist * dist);
      let fx = (dx / dist) * force;
      let fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Spring forces along edges
  for (let i = 0; i < edges.length; i++) {
    let nodeA = findNode(edges[i].a);
    let nodeB = findNode(edges[i].b);
    if (!nodeA || !nodeB) continue;
    let dx = nodeB.x - nodeA.x;
    let dy = nodeB.y - nodeA.y;
    let dist = Math.sqrt(dx * dx + dy * dy) || 1;
    let displacement = dist - edges[i].rest;
    let force = (edges[i].k || config.springK) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Apply gravity toward center, damping, and update positions
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * config.gravity;
    nodes[i].vy += (300 - nodes[i].y) * config.gravity;
    nodes[i].vx *= config.damping;
    nodes[i].vy *= config.damping;
    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

// Spawn a decorative particle from a random node
function spawnParticle() {
  if (particles.length >= config.particleMax) return;
  let node = nodes[Math.floor(Math.random() * nodes.length)];
  let angle = Math.random() * TWO_PI;
  let speed = 0.3 + Math.random() * 0.7;
  particles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * 1.2
  });
}

// Update all particles
function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.vx *= 0.995;
    p.vy *= 0.995;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// Smooth camera interpolation
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.cameraEase;
  camera.y += (cameraTarget.y - camera.y) * config.cameraEase;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.cameraEase;
}

// Main loop
function tick() {
  simulatePhysics();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();
  updateParticles();
  frameCount++;
}

setInterval(tick, 16); // ~60fps
```

## What It Does

This is a **force-directed graph layout simulation** — a common visualization technique for network/graph data. Specifically:

### 🔵 Graph Structure
- **6 nodes** ("Hub", "Alpha", "Beta", "Gamma", "Delta", "Epsilon") connected by **8 edges** forming a hub-and-spoke topology centered on "Hub"

### ⚙️ Physics Engine
The simulation runs three forces every frame:
1. **Repulsion** — All nodes repel each other (inverse-square law, like electrostatic force) to prevent overlap
2. **Spring attraction** — Connected nodes are pulled toward each other via Hooke's law with configurable rest lengths and stiffness
3. **Centering gravity** — A weak force pulls all nodes toward the canvas center (400, 300)
4. **Velocity damping** (0.92×) prevents oscillation

### ✨ Particles
Decorative particles spawn from random nodes every 3 frames, drift outward with friction (0.995×), and die after 800–2000 frames — creating a glowing ambient effect.

### 🎥 Camera
A virtual camera smoothly eases toward a target position/zoom using linear interpolation (lerp at 6% per frame).

### 🔄 Main Loop
`setInterval` at 16ms (~60fps) drives: physics → camera → particle spawning → particle updates.

> **Note:** This is the simulation/logic layer only — there's no rendering code here. It would typically be paired with a Canvas or WebGL renderer that draws the nodes, edges, and particles each frame.
